from flask import Flask, request, jsonify
from flask_graphql import GraphQLView
from graphene import ObjectType, String, Int, List, Schema, Field

class Product(ObjectType):
    id = Int()
    name = String()
    price = Int()
    category_id = Int()

class Category(ObjectType):
    id = Int()
    name = String()

class Review(ObjectType):
    id = Int()
    product_id = Int()
    user_id = Int()
    content = String()

class Query(ObjectType):
    products = List(Product)
    categories = List(Category)
    reviews = List(Review)

    def resolve_products(self, info):
        # Sample data
        return [
            Product(id=1, name="Laptop", price=1000, category_id=1),
            Product(id=2, name="Smartphone", price=500, category_id=2)
        ]

    def resolve_categories(self, info):
        # Sample data
        return [
            Category(id=1, name="Electronics"),
            Category(id=2, name="Mobile Devices")
        ]

    def resolve_reviews(self, info):
        # Sample data
        return [
            Review(id=1, product_id=1, user_id=1, content="Great product!"),
            Review(id=2, product_id=2, user_id=2, content="Good value for money.")
        ]

schema = Schema(query=Query)

app = Flask(__name__)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True  # Enable GraphiQL for testing
    )
)

@app.route('/graphql', methods=['POST'])
def graphql_post():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'No input data provided'}), 400
    result = schema.execute(data.get('query'), variables=data.get('variables'))
    return jsonify(result.data)

if __name__ == '__main__':
    app.run(debug=True)